import React, { useState, useMemo } from 'react';
import {
  Calculator, ArrowRight, BookOpen, BarChart3,
  Table, List, Info, CheckCircle2, AlertCircle,
  RefreshCw, Download, Copy, Layout,
  BarChart, PieChart, LineChart, Hash
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import SolutionStep from '../../components/SolutionStep';
import { BlockMath, InlineMath } from 'react-katex';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
} from 'chart.js';
import { Bar, Line } from 'react-chartjs-2';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const BasicStats = ({ isDarkMode, addToHistory, copyResult }) => {
  const [input, setInput] = useState('15, 22, 15, 34, 45, 22, 15, 56');
  const [zValue, setZValue] = useState('');
  const [activeChart, setActiveChart] = useState('histogram'); // 'histogram' or 'distribution'


  const sampleDatasets = [
    { name: 'Test Scores', data: '85, 92, 78, 95, 88, 90, 82, 89' },
    { name: 'Heights (cm)', data: '165, 172, 168, 180, 175, 170, 169, 174' },
    { name: 'Temperatures', data: '22, 24, 21, 25, 23, 22, 26, 24' }
  ];

  const stats = useMemo(() => {
    const rawNumbers = input.split(/[, \s]+/)
      .map(n => parseFloat(n))
      .filter(n => !isNaN(n));

    if (rawNumbers.length === 0) return null;

    const numbers = [...rawNumbers].sort((a, b) => a - b);
    const count = numbers.length;
    const sum = numbers.reduce((a, b) => a + b, 0);
    const mean = sum / count;

    // Median
    const mid = Math.floor(count / 2);
    const median = count % 2 !== 0
      ? numbers[mid]
      : (numbers[mid - 1] + numbers[mid]) / 2;

    // Mode
    const freqMap = {};
    let maxFreq = 0;
    numbers.forEach(n => {
      freqMap[n] = (freqMap[n] || 0) + 1;
      if (freqMap[n] > maxFreq) maxFreq = freqMap[n];
    });
    const modes = Object.keys(freqMap)
      .filter(n => freqMap[n] === maxFreq && maxFreq > 1)
      .map(Number);

    // Variance & Std Dev
    const deviations = rawNumbers.map(n => ({
      val: n,
      diff: n - mean,
      diffSq: Math.pow(n - mean, 2)
    }));
    const sumSqDiffs = deviations.reduce((a, b) => a + b.diffSq, 0);
    const popVariance = sumSqDiffs / count;
    const sampleVariance = count > 1 ? sumSqDiffs / (count - 1) : 0;
    const popStdDev = Math.sqrt(popVariance);
    const sampleStdDev = Math.sqrt(sampleVariance);

    // Quartiles
    const getMedian = (arr) => {
      const m = Math.floor(arr.length / 2);
      return arr.length % 2 !== 0 ? arr[m] : (arr[m - 1] + arr[m]) / 2;
    };
    const q1 = getMedian(numbers.slice(0, mid));
    const q3 = getMedian(numbers.slice(count % 2 === 0 ? mid : mid + 1));
    const iqr = q3 - q1;

    // Z-Score
    const targetZ = parseFloat(zValue);
    const zScore = !isNaN(targetZ) ? (targetZ - mean) / popStdDev : null;

    return {
      rawNumbers, numbers, sum, mean, median, modes, freqMap, maxFreq,
      count, popVariance, sampleVariance, popStdDev, sampleStdDev,
      q1, q3, iqr, min: numbers[0], max: numbers[count - 1],
      range: numbers[count - 1] - numbers[0], zScore, deviations
    };
  }, [input, zValue]);

  // Chart Data
  const histogramData = useMemo(() => {
    if (!stats) return null;
    const labels = Object.keys(stats.freqMap).sort((a, b) => Number(a) - Number(b));
    const data = labels.map(l => stats.freqMap[l]);

    return {
      labels,
      datasets: [{
        label: 'Frequency',
        data,
        backgroundColor: 'rgba(59, 130, 246, 0.5)',
        borderColor: '#3b82f6',
        borderWidth: 2,
        borderRadius: 8,
      }]
    };
  }, [stats]);

  const distributionData = useMemo(() => {
    if (!stats) return null;
    const xValues = [];
    const yValues = [];
    const { mean, popStdDev } = stats;

    for (let x = mean - 4 * popStdDev; x <= mean + 4 * popStdDev; x += popStdDev / 10) {
      const y = (1 / (popStdDev * Math.sqrt(2 * Math.PI))) * Math.exp(-0.5 * Math.pow((x - mean) / popStdDev, 2));
      xValues.push(x.toFixed(2));
      yValues.push(y);
    }

    return {
      labels: xValues,
      datasets: [{
        label: 'Normal Distribution',
        data: yValues,
        borderColor: '#8b5cf6',
        backgroundColor: 'rgba(139, 92, 246, 0.1)',
        fill: true,
        tension: 0.4,
        pointRadius: 0,
      }]
    };
  }, [stats]);

  // Sync with history when stats change
  React.useEffect(() => {
    if (stats && stats.count > 0) {
      addToHistory(`Mean: ${stats.mean.toFixed(2)} (n=${stats.count})`);
    }
  }, [stats?.mean, stats?.count]);

  return (
    <div className="space-y-8">
      {/* AdSense Top Banner */}
      <div className="ad-slot w-full p-4 bg-gray-100 dark:bg-gray-800 border border-dashed border-gray-400 dark:border-gray-600 rounded-lg text-center text-gray-500 dark:text-gray-400 text-sm">
        <p className="font-bold">Advertisement</p>
        <p>728 x 90 Leaderboard</p>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        {/* Input Section */}
        <div className="lg:col-span-2 space-y-6">
          <div className={`p-8 rounded-3xl border shadow-xl ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'} backdrop-blur-md`}>
            <div className="flex items-center justify-between mb-6">
              <h3 className={`text-xl font-black ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Data Entry</h3>
              <div className="flex gap-2">
                {sampleDatasets.map((ds) => (
                  <button
                    key={ds.name}
                    onClick={() => setInput(ds.data)}
                    className="px-3 py-1.5 rounded-lg text-xs font-bold bg-blue-500/10 text-blue-500 border border-blue-500/20 hover:bg-blue-500/20 transition-all"
                  >
                    {ds.name}
                  </button>
                ))}
              </div>
            </div>

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              className={`w-full px-6 py-4 rounded-2xl border-2 outline-none transition-all text-lg font-mono min-h-[150px] ${isDarkMode
                  ? 'bg-gray-900/50 border-gray-700 text-white focus:border-blue-500'
                  : 'bg-white border-gray-200 text-gray-900 focus:border-blue-500'
                }`}
              placeholder="Enter numbers separated by commas or spaces..."
            />

            <div className="mt-4 flex items-center justify-between text-xs font-bold text-gray-400 uppercase">
              <span>Data Points: {stats?.count || 0}</span>
              <span>Valid Numbers Only</span>
            </div>
          </div>

          {/* Ad Slot between input and results */}
          <div className="ad-slot w-full h-32 bg-gray-50 dark:bg-gray-900/50 border border-dashed border-gray-300 dark:border-gray-700 rounded-2xl flex items-center justify-center text-gray-400 text-sm">
            Ad Space (300x250)
          </div>

          {/* Results Grid */}
          {stats && (
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              {[
                { label: 'Mean', value: stats.mean.toFixed(2), icon: Hash, color: 'blue' },
                { label: 'Median', value: stats.median.toFixed(2), icon: List, color: 'indigo' },
                { label: 'Mode', value: stats.modes.length > 0 ? stats.modes.join(', ') : 'None', icon: RefreshCw, color: 'purple' },
                { label: 'Range', value: stats.range, icon: Maximize2, color: 'pink' },
                { label: 'Std Dev (σ)', value: stats.popStdDev.toFixed(4), icon: BarChart3, color: 'blue' },
                { label: 'Variance (σ²)', value: stats.popVariance.toFixed(4), icon: Layout, color: 'blue' },
                { label: 'Q1', value: stats.q1.toFixed(2), icon: Minimize2, color: 'indigo' },
                { label: 'Q3', value: stats.q3.toFixed(2), icon: Maximize2, color: 'indigo' }
              ].map((item, idx) => (
                <motion.div
                  key={idx}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: idx * 0.05 }}
                  className={`p-5 rounded-2xl border relative group/item ${isDarkMode ? 'bg-gray-800/40 border-gray-700' : 'bg-white border-gray-200'
                    } shadow-sm`}
                >
                  <button
                    onClick={() => copyResult(item.value)}
                    className="absolute right-2 top-2 p-1 rounded-md bg-blue-500/10 opacity-0 group-hover/item:opacity-100 transition-all"
                    title="Copy Value"
                  >
                    <Copy size={12} className="text-blue-500" />
                  </button>
                  <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${isDarkMode ? `bg-${item.color}-500/20 text-${item.color}-400` : `bg-${item.color}-50 text-${item.color}-600`
                    }`}>
                    <item.icon size={16} />
                  </div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{item.label}</p>
                  <h4 className={`text-lg font-black truncate ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{item.value}</h4>
                </motion.div>
              ))}
            </div>
          )}
        </div>

        {/* Sidebar: Z-Score & Visuals */}
        <div className="space-y-6">
          <div className={`p-8 rounded-3xl border shadow-xl ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'} backdrop-blur-md`}>
            <h3 className="text-sm font-bold uppercase text-blue-500 mb-6 flex items-center gap-2">
              <Calculator size={16} /> Z-Score Calculator
            </h3>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Value (x)</label>
                <input
                  type="number"
                  value={zValue}
                  onChange={(e) => setZValue(e.target.value)}
                  placeholder="Enter value"
                  className={`w-full px-4 py-3 rounded-xl border-2 transition-all outline-none focus:border-blue-500 ${isDarkMode ? 'bg-gray-900/50 border-gray-700 text-white' : 'bg-white border-gray-200 text-gray-900'
                    }`}
                />
              </div>
              {stats?.zScore !== null && (
                <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className={`p-4 rounded-xl border-2 ${isDarkMode ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' : 'bg-blue-50 border-blue-100 text-blue-600'}`}>
                  <p className="text-[10px] font-bold uppercase mb-1">Standardized Z-Score</p>
                  <p className="text-3xl font-black">{stats.zScore.toFixed(4)}</p>
                </motion.div>
              )}
            </div>
          </div>

          {/* Visualizer Sidebar */}
          <div className={`p-8 rounded-3xl border shadow-xl ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'} backdrop-blur-md`}>
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-sm font-bold uppercase text-purple-500 flex items-center gap-2">
                <BarChart size={16} /> Visualizer
              </h3>
              <div className="flex p-1 rounded-lg bg-gray-100 dark:bg-gray-900/50 border border-gray-200 dark:border-gray-700">
                <button onClick={() => setActiveChart('histogram')} className={`p-1.5 rounded-md transition-all ${activeChart === 'histogram' ? 'bg-white dark:bg-gray-700 shadow-sm text-blue-500' : 'text-gray-400'}`}><BarChart size={14} /></button>
                <button onClick={() => setActiveChart('distribution')} className={`p-1.5 rounded-md transition-all ${activeChart === 'distribution' ? 'bg-white dark:bg-gray-700 shadow-sm text-purple-500' : 'text-gray-400'}`}><LineChart size={14} /></button>
              </div>
            </div>

            <div className="h-[250px] w-full flex items-center justify-center">
              {stats ? (
                activeChart === 'histogram' ? (
                  <Bar data={histogramData} options={{ responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } } }} />
                ) : (
                  <Line data={distributionData} options={{ responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } } }} />
                )
              ) : (
                <p className="text-gray-400 text-xs italic">Enter data to visualize</p>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Solution Engine */}
      {stats && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className={`p-10 rounded-3xl border shadow-xl ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'} backdrop-blur-md`}
        >
          <div className="flex items-center space-x-4 mb-10">
            <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white shadow-lg">
              <CheckCircle2 size={28} />
            </div>
            <div>
              <h2 className={`text-3xl font-black ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Solution Engine</h2>
              <p className="text-gray-500 font-medium">Step-by-step statistical breakdown</p>
            </div>
          </div>

          <div className="space-y-0">
            <SolutionStep
              stepNumber={1}
              title="Data Preparation"
              description={`First, we clean and sort the input data. We have ${stats.count} valid numbers.`}
              isDarkMode={isDarkMode}
            />

            <SolutionStep
              stepNumber={2}
              title="Calculate Arithmetic Mean (μ)"
              description={`Sum all numbers and divide by the count ($n = ${stats.count}$).`}
              formula={`\\mu = \\frac{\\sum x}{n} = \\frac{${stats.sum}}{${stats.count}} = ${stats.mean.toFixed(2)}`}
              isDarkMode={isDarkMode}
            />

            <SolutionStep
              stepNumber={3}
              title="Determine Median & Mode"
              description={`The sorted middle value is ${stats.median.toFixed(2)}. The most frequent value(s): ${stats.modes.length > 0 ? stats.modes.join(', ') : 'None'}.`}
              isDarkMode={isDarkMode}
            />

            <SolutionStep
              stepNumber={4}
              title="Calculate Variance & Standard Deviation"
              description="Calculate squared deviations from the mean, sum them, and take the square root."
              formula={`\\sigma = \\sqrt{\\frac{\\sum(x - \\mu)^2}{n}} = \\sqrt{${stats.popVariance.toFixed(4)}} = ${stats.popStdDev.toFixed(4)}`}
              isLast={true}
              isDarkMode={isDarkMode}
            />
          </div>

          {/* Deviation Table */}
          <div className="mt-10 overflow-x-auto rounded-2xl border border-gray-200 dark:border-gray-700">
            <table className="w-full text-left text-sm">
              <thead className={`${isDarkMode ? 'bg-gray-900/50' : 'bg-gray-50'} border-b border-gray-200 dark:border-gray-700`}>
                <tr>
                  <th className="px-6 py-4 font-bold">Value (x)</th>
                  <th className="px-6 py-4 font-bold">Deviation (x - μ)</th>
                  <th className="px-6 py-4 font-bold">Sq. Deviation (x - μ)²</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                {stats.deviations.slice(0, 10).map((d, i) => (
                  <tr key={i}>
                    <td className="px-6 py-4 font-mono">{d.val}</td>
                    <td className="px-6 py-4 font-mono text-blue-500">{d.diff.toFixed(2)}</td>
                    <td className="px-6 py-4 font-mono text-purple-500">{d.diffSq.toFixed(2)}</td>
                  </tr>
                ))}
                {stats.deviations.length > 10 && (
                  <tr>
                    <td colSpan="3" className="px-6 py-4 text-center text-gray-400 italic">... showing first 10 entries ...</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </motion.div>
      )}

      {/* SEO Article */}
      <article className={`p-10 rounded-3xl border shadow-xl ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'}`}>
        <div className="flex items-center space-x-4 mb-8">
          <div className={`p-3 rounded-2xl ${isDarkMode ? 'bg-blue-900/30 text-blue-400' : 'bg-blue-100 text-blue-600'}`}>
            <Info size={24} />
          </div>
          <h2 className={`text-4xl font-black ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Statistical Literacy Guide</h2>
        </div>

        <div className={`prose prose-lg max-w-none ${isDarkMode ? 'prose-invert prose-gray-300' : 'prose-gray-600'}`}>
          <p>
            Statistics is the language of modern data science. Whether you're analyzing experimental results
            or financial markets, understanding central tendency and dispersion is essential.
          </p>

          <div className="grid md:grid-cols-2 gap-8 my-10">
            <div className={`p-6 rounded-2xl border ${isDarkMode ? 'bg-gray-900/50 border-gray-700' : 'bg-gray-50 border-gray-200'}`}>
              <h4 className="font-bold text-blue-500 mb-2">Mean vs Median</h4>
              <p className="text-sm">The mean is sensitive to outliers (extremely high or low values), while the median is more robust. In skewed data like household income, the median often provides a better "typical" value.</p>
            </div>
            <div className={`p-6 rounded-2xl border ${isDarkMode ? 'bg-gray-900/50 border-gray-700' : 'bg-gray-50 border-gray-200'}`}>
              <h4 className="font-bold text-purple-500 mb-2">Standard Deviation</h4>
              <p className="text-sm">Standard deviation (σ) measures the average distance of data points from the mean. A low σ indicates data points are close to the mean, while a high σ indicates they are spread out.</p>
            </div>
          </div>

          <h3 className="text-2xl font-bold mt-10 mb-4">When to use Z-Scores</h3>
          <p>
            A Z-score allows you to compare data points from different normal distributions. It tells you
            how many standard deviations a point is from the mean. This is how standardized tests like the
            SAT are compared across different versions of the exam.
          </p>
        </div>
      </article>

      {/* AdSense Bottom Banner */}
      <div className="ad-slot w-full h-32 bg-gray-100 dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700 flex items-center justify-center">
        <div className="text-gray-500 dark:text-gray-400 text-center">
          <p className="text-sm font-bold">Ads Go Here</p>
          <p className="text-xs">Bottom Banner - 728x90 px</p>
        </div>
      </div>
    </div>
  );
};

export default BasicStats;

import React, { useState, useMemo, useEffect } from 'react';
import {
  Calculator, ArrowRight, BookOpen, Variable,
  LineChart as ChartIcon, Keyboard, Info,
  FunctionSquare, ChevronDown, ChevronUp, AlertCircle
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import SolutionStep from '../../components/SolutionStep';
import { BlockMath, InlineMath } from 'react-katex';
import * as math from 'mathjs';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Line } from 'react-chartjs-2';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const CalculusSolver = ({ isDarkMode, addToHistory, copyResult }) => {
  const [activeTab, setActiveTab] = useState('derivative'); // 'derivative' or 'limit'
  const [expression, setExpression] = useState('x^2 + 3x + 5');
  const [variable, setVariable] = useState('x');
  const [order, setOrder] = useState(1);
  const [limitValue, setLimitValue] = useState('0');
  const [limitDirection, setLimitDirection] = useState('both'); // 'left', 'right', 'both'
  const [showWhyWorks, setShowWhyWorks] = useState(false);


  // Keyboard helper
  const addToExpression = (val) => {
    setExpression(prev => prev + val);
  };

  const commonFunctions = [
    { label: 'sin', value: 'sin(' },
    { label: 'cos', value: 'cos(' },
    { label: 'tan', value: 'tan(' },
    { label: 'log', value: 'log(' },
    { label: 'ln', value: 'log(' },
    { label: 'exp', value: 'exp(' },
    { label: '√', value: 'sqrt(' },
    { label: '^', value: '^' },
    { label: 'π', value: 'pi' },
    { label: 'e', value: 'e' },
    { label: '(', value: '(' },
    { label: ')', value: ')' },
  ];

  // Derivative Logic
  const derivativeResult = useMemo(() => {
    if (activeTab !== 'derivative') return null;
    try {
      let currentDeriv = expression;
      const steps = [];

      // Step 1: Identification
      steps.push({
        title: 'Identify the Function',
        description: `We are finding the ${order === 1 ? 'first' : order === 2 ? 'second' : 'third'} derivative of $f(${variable}) = ${expression}$ with respect to $${variable}$.`,
        formula: `\\frac{d^{${order}}}{d${variable}^{${order}}}(${math.parse(expression).toTex()})`
      });

      // Iterative derivation for orders
      for (let i = 1; i <= order; i++) {
        const deriv = math.derivative(currentDeriv, variable);
        const simplified = math.simplify(deriv).toString();

        if (order > 1) {
          steps.push({
            title: `Order ${i} Derivation`,
            description: i === 1 ? 'First, we find the first derivative.' : `Next, we differentiate the previous result.`,
            formula: `\\frac{d}{d${variable}}(${math.parse(currentDeriv).toTex()}) = ${math.parse(simplified).toTex()}`
          });
        }
        currentDeriv = simplified;
      }

      // Final Step Logic
      const node = math.parse(currentDeriv);
      steps.push({
        title: 'Final Simplification',
        description: 'Applying the power rule and sum rule where applicable, we get the final result.',
        formula: `f^{(${order})}(${variable}) = ${node.toTex()}`,
        isLast: true
      });

      return {
        result: currentDeriv,
        latex: node.toTex(),
        steps,
        error: null
      };
    } catch (err) {
      return { error: 'Invalid expression for derivation' };
    }
  }, [expression, variable, order, activeTab]);

  // Limit Logic
  const limitResult = useMemo(() => {
    if (activeTab !== 'limit') return null;
    try {
      const steps = [];
      const f = math.parse(expression).compile();
      const val = math.evaluate(limitValue);

      steps.push({
        title: 'Direct Substitution',
        description: `Substitute $${variable} = ${limitValue}$ into the function.`,
        formula: `f(${limitValue}) = ${expression.replace(new RegExp(variable, 'g'), `(${limitValue})`)}`
      });

      let finalResult;
      let error = null;

      try {
        const substitutedValue = f.evaluate({ [variable]: val });
        if (isNaN(substitutedValue) || !isFinite(substitutedValue)) {
          throw new Error('Indeterminate');
        }
        finalResult = substitutedValue.toString();
        steps.push({
          title: 'Limit Found',
          description: 'The function is continuous at this point, so the limit equals the function value.',
          formula: `\\lim_{${variable} \\to ${limitValue}} f(${variable}) = ${finalResult}`,
          isLast: true
        });
      } catch (e) {
        // Handle 0/0 or Infinity
        steps.push({
          title: 'Handle Indeterminate Form',
          description: 'Direct substitution resulted in an indeterminate form (0/0 or ∞/∞). We should look for factoring or L\'Hôpital\'s Rule.',
          formula: '\\text{Form: } \\frac{0}{0} \\text{ or } \\frac{\\infty}{\\infty}'
        });

        // Approximation for limit
        const eps = 0.000001;
        const leftVal = f.evaluate({ [variable]: val - eps });
        const rightVal = f.evaluate({ [variable]: val + eps });

        if (limitDirection === 'left') finalResult = leftVal.toFixed(4);
        else if (limitDirection === 'right') finalResult = rightVal.toFixed(4);
        else {
          if (Math.abs(leftVal - rightVal) < 0.01) finalResult = ((leftVal + rightVal) / 2).toFixed(4);
