const IntegralCalculator = ({ isDarkMode, addToHistory, copyResult }) => {
  const [activeTab, setActiveTab] = useState('indefinite'); // 'indefinite' or 'definite'
  const [expression, setExpression] = useState('x^2 + 2x');
  const [variable, setVariable] = useState('x');
  const [lowerBound, setLowerBound] = useState('0');
  const [upperBound, setUpperBound] = useState('2');
  const [showCheatSheet, setShowCheatSheet] = useState(false);
  const [practiceProblem, setPracticeProblem] = useState(null);


  // Keyboard helper
  const addToExpression = (val) => {
    setExpression(prev => prev + val);
  };

  const commonFunctions = [
    { label: 'sin', value: 'sin(' },
    { label: 'cos', value: 'cos(' },
    { label: 'tan', value: 'tan(' },
    { label: 'eˣ', value: 'exp(' },
    { label: 'ln', value: 'log(' },
    { label: '√', value: 'sqrt(' },
    { label: '^', value: '^' },
    { label: '(', value: '(' },
    { label: ')', value: ')' },
    { label: 'x', value: 'x' },
    { label: 'π', value: 'pi' },
  ];

  // Symbolic Integration Helper (Basic Rule-Based)
  const symbolicIntegrate = (expr, v) => {
    try {
      const node = math.parse(expr);

      // Recursive function to integrate common nodes
      const integrateNode = (n) => {
        // Handle OperatorNode (Sum, Difference)
        if (n.type === 'OperatorNode' && (n.op === '+' || n.op === '-')) {
          const left = integrateNode(n.args[0]);
          const right = integrateNode(n.args[1]);
          return new math.OperatorNode(n.op, n.fn, [left, right]);
        }

        // Handle Constant * Function
        if (n.type === 'OperatorNode' && n.op === '*') {
          if (n.args[0].type === 'ConstantNode') {
            return new math.OperatorNode('*', 'multiply', [n.args[0], integrateNode(n.args[1])]);
          }
          if (n.args[1].type === 'ConstantNode') {
            return new math.OperatorNode('*', 'multiply', [integrateNode(n.args[0]), n.args[1]]);
          }
        }

        // Handle x^n (Power Rule)
        if (n.type === 'OperatorNode' && n.op === '^') {
          if (n.args[0].type === 'SymbolNode' && n.args[0].name === v && n.args[1].type === 'ConstantNode') {
            const power = parseFloat(n.args[1].value);
            if (power === -1) return math.parse(`log(abs(${v}))`);
            const newPower = power + 1;
            return math.parse(`(${v}^${newPower})/${newPower}`);
          }
        }

        // Handle x (Power Rule n=1)
        if (n.type === 'SymbolNode' && n.name === v) {
          return math.parse(`(${v}^2)/2`);
        }

        // Handle Constant (c -> cx)
        if (n.type === 'ConstantNode') {
          return new math.OperatorNode('*', 'multiply', [n, new math.SymbolNode(v)]);
        }

        // Handle Basic Functions
        if (n.type === 'FunctionNode') {
          if (n.name === 'sin' && n.args[0].name === v) return math.parse(`-cos(${v})`);
          if (n.name === 'cos' && n.args[0].name === v) return math.parse(`sin(${v})`);
          if (n.name === 'exp' && n.args[0].name === v) return math.parse(`exp(${v})`);
          if (n.name === 'log' && n.args[0].name === v) return math.parse(`(${v}*log(${v}) - ${v})`);
        }

        throw new Error('Unsupported expression for symbolic integration');
      };

      const integratedNode = integrateNode(node);
      return math.simplify(integratedNode).toString();
    } catch (e) {
      return null;
    }
  };

  const result = useMemo(() => {
    try {
      const steps = [];
      const antiderivative = symbolicIntegrate(expression, variable);

      if (activeTab === 'indefinite') {
        if (!antiderivative) return { error: 'Symbolic integration limited to polynomials, sin, cos, and exp' };

        steps.push({
          title: 'Identify Integration Rules',
          description: `We are integrating $f(${variable}) = ${expression}$. We will apply the power rule and standard integral forms.`,
          formula: `\\int (${math.parse(expression).toTex()}) \\, d${variable}`
        });

        steps.push({
          title: 'Integrate Term-by-Term',
          description: 'Applying the Sum Rule: the integral of a sum is the sum of the integrals.',
          formula: `\\int f(${variable}) \\, d${variable} = ${math.parse(antiderivative).toTex()} + C`
        });

        return {
          result: `${antiderivative} + C`,
          latex: `${math.parse(antiderivative).toTex()} + C`,
          steps,
          error: null
        };
      } else {
        // Definite Integral
        const f = math.parse(expression).compile();
        const a = math.evaluate(lowerBound);
        const b = math.evaluate(upperBound);

        steps.push({
          title: 'Find the Antiderivative',
          description: `First, find the indefinite integral $F(${variable})$.`,
          formula: `F(${variable}) = ${antiderivative ? math.parse(antiderivative).toTex() : '\\text{Integrated Form}'}`
        });

        steps.push({
          title: 'Apply Fundamental Theorem of Calculus',
          description: 'Evaluate the antiderivative at the upper and lower bounds.',
          formula: `\\int_{${lowerBound}}^{${upperBound}} f(${variable}) \\, d${variable} = F(${upperBound}) - F(${lowerBound})`
        });

        // Numerical evaluation for the final value
        // Using a simple Simpson's rule or similar via mathjs if possible
        // For now, we evaluate at bounds if antiderivative exists, else numerical approx
        let finalValue;
        if (antiderivative) {
          const F = math.parse(antiderivative).compile();
          finalValue = (F.evaluate({ [variable]: b }) - F.evaluate({ [variable]: a }));
        } else {
          // Numerical fallback
          const samples = 100;
          const h = (b - a) / samples;
          let sum = 0.5 * (f.evaluate({ [variable]: a }) + f.evaluate({ [variable]: b }));
          for (let i = 1; i < samples; i++) {
            sum += f.evaluate({ [variable]: a + i * h });
          }
          finalValue = sum * h;
        }

        steps.push({
          title: 'Calculate Final Value',
          description: 'Substitute the bounds and simplify to get the net area.',
          formula: `\\text{Area} = ${finalValue.toFixed(4)}`,
          isLast: true
        });

        return {
          result: finalValue.toFixed(4),
          latex: `\\int_{${lowerBound}}^{${upperBound}} (${math.parse(expression).toTex()}) \\, d${variable}`,
          steps,
          error: null
        };
      }
    } catch (err) {
      return { error: 'Invalid expression or calculation error' };
    }
  }, [expression, variable, activeTab, lowerBound, upperBound]);

  // Chart Data for Definite Integral
  const chartData = useMemo(() => {
    if (activeTab !== 'definite') return null;
    try {
      const f = math.parse(expression).compile();
      const a = math.evaluate(lowerBound);
      const b = math.evaluate(upperBound);
      const xValues = [];
      const yValues = [];
      const fillValues = [];

      const padding = Math.abs(b - a) * 0.5;
      const start = a - padding;
      const end = b + padding;
      const step = (end - start) / 100;

      for (let x = start; x <= end; x += step) {
        const y = f.evaluate({ [variable]: x });
        xValues.push(x.toFixed(2));
        yValues.push(y);
        fillValues.push(x >= a && x <= b ? y : null);
      }

      return {
        labels: xValues,
        datasets: [
          {
            label: 'Function f(x)',
            data: yValues,
            borderColor: '#3b82f6',
            borderWidth: 2,
            pointRadius: 0,
            tension: 0.4,
          },
          {
            label: 'Shaded Area',
            data: fillValues,
            backgroundColor: 'rgba(59, 130, 246, 0.3)',
            fill: true,
            pointRadius: 0,
            tension: 0.4,
          }
        ]
      };
    } catch (e) {
      return null;
    }
  }, [expression, variable, activeTab, lowerBound, upperBound]);

  const generatePracticeProblem = () => {
    const problems = [
      { expr: '3x^2 + 4x', var: 'x', type: 'indefinite' },
      { expr: 'sin(x)', var: 'x', type: 'definite', a: '0', b: 'pi' },
      { expr: 'exp(x)', var: 'x', type: 'definite', a: '0', b: '1' },
      { expr: 'x^3 - 2x + 5', var: 'x', type: 'indefinite' },
      { expr: 'cos(x)', var: 'x', type: 'definite', a: '0', b: 'pi/2' }
    ];
    const problem = problems[Math.floor(Math.random() * problems.length)];
    setExpression(problem.expr);
    setVariable(problem.var);
    setActiveTab(problem.type);
    if (problem.type === 'definite') {
      setLowerBound(problem.a);
      setUpperBound(problem.b);
    }
    setPracticeProblem(problem);
  };

  // Sync with history when result changes
  useEffect(() => {
    if (result && !result.error) {
      const resString = activeTab === 'indefinite'
        ? result.result
        : `Definite Integral [${lowerBound}, ${upperBound}] = ${result.result}`;
      addToHistory(resString);
    }
  }, [result?.result, activeTab]);

  return (
    <div className="space-y-8">
      {/* Desktop Ad Slot (Skyscraper) */}
      <div className="hidden lg:block fixed left-4 top-1/2 -translate-y-1/2 w-[300px] h-[600px] bg-gray-100 dark:bg-gray-800 border border-dashed border-gray-400 dark:border-gray-600 rounded-lg flex items-center justify-center text-gray-500 text-sm">
        <p className="font-bold rotate-90 whitespace-nowrap">Desktop Skyscraper Ad - 300x600</p>
      </div>

      {/* Mobile Ad Slot */}
      <div className="lg:hidden ad-slot w-full p-4 bg-gray-100 dark:bg-gray-800 border border-dashed border-gray-400 dark:border-gray-600 rounded-lg text-center text-gray-500 text-sm">
        <p className="font-bold">Mobile Rectangle Ad - 300x250</p>
      </div>

      {/* Main Calculator */}
      <div className={`backdrop-blur-xl rounded-3xl border shadow-2xl overflow-hidden ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'
        }`}>
        <div className="flex border-b border-gray-200 dark:border-gray-700">
          <button
            onClick={() => setActiveTab('indefinite')}
            className={`flex-1 py-4 text-sm font-bold transition-all flex items-center justify-center space-x-2 ${activeTab === 'indefinite'
                ? 'bg-blue-600 text-white'
                : 'text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700'
              }`}
          >
            <Sigma size={18} />
            <span>Indefinite Integral</span>
          </button>
          <button
            onClick={() => setActiveTab('definite')}
            className={`flex-1 py-4 text-sm font-bold transition-all flex items-center justify-center space-x-2 ${activeTab === 'definite'
                ? 'bg-blue-600 text-white'
                : 'text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700'
              }`}
          >
            <Calculator size={18} />
            <span>Definite Integral</span>
          </button>
        </div>

        <div className="p-8">
          <div className="grid lg:grid-cols-2 gap-12">
            {/* Left Column: Input */}
            <div className="space-y-6">
              <div>
                <label className={`block text-sm font-bold mb-3 ${isDarkMode ? 'text-gray-400' : 'text-gray-600'}`}>
                  Function to Integrate ∫ f({variable}) d{variable}
                </label>
                <div className="relative group">
                  <input
                    type="text"
                    value={expression}
                    onChange={(e) => setExpression(e.target.value)}
                    className={`w-full px-6 py-4 rounded-2xl border-2 outline-none transition-all text-lg font-mono ${isDarkMode
                        ? 'bg-gray-900/50 border-gray-700 text-white focus:border-blue-500'
                        : 'bg-white border-gray-200 text-gray-900 focus:border-blue-500'
                      }`}
                    placeholder="e.g., x^2 + 2x"
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 opacity-50">
                    <Keyboard size={20} />
                  </div>
                </div>

                {/* Math Preview */}
                <div className="mt-4 p-4 rounded-2xl bg-blue-500/5 border border-blue-500/10 min-h-[60px] flex items-center justify-center">
                  <div className="overflow-x-auto text-xl">
                    <BlockMath math={activeTab === 'indefinite'
                      ? `\\int (${math.parse(expression).toTex()}) \\, d${variable}`
                      : `\\int_{${lowerBound}}^{${upperBound}} (${math.parse(expression).toTex()}) \\, d${variable}`
                    } />
                  </div>
                </div>
              </div>

              {/* Definite Bounds */}
              <AnimatePresence>
                {activeTab === 'definite' && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: 'auto', opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    className="grid grid-cols-2 gap-4"
                  >
                    <div>
                      <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Lower Bound (a)</label>
                      <input
                        type="text"
                        value={lowerBound}
                        onChange={(e) => setLowerBound(e.target.value)}
                        className={`w-full px-4 py-3 rounded-xl border ${isDarkMode ? 'bg-gray-900/50 border-gray-700' : 'bg-gray-50 border-gray-200'}`}
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Upper Bound (b)</label>
                      <input
                        type="text"
                        value={upperBound}
                        onChange={(e) => setUpperBound(e.target.value)}
                        className={`w-full px-4 py-3 rounded-xl border ${isDarkMode ? 'bg-gray-900/50 border-gray-700' : 'bg-gray-50 border-gray-200'}`}
                      />
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>

              {/* Scientific Input Buttons */}
              <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                {commonFunctions.map((btn) => (
                  <button
                    key={btn.label}
                    onClick={() => addToExpression(btn.value)}
                    className={`p-3 rounded-xl border text-sm font-bold transition-all ${isDarkMode
                        ? 'bg-gray-800 border-gray-700 text-gray-300 hover:bg-gray-700 hover:text-white'
                        : 'bg-gray-50 border-gray-200 text-gray-600 hover:bg-white hover:shadow-md'
                      }`}
                  >
                    {btn.label}
                  </button>
                ))}
                <button
                  onClick={generatePracticeProblem}
                  className="p-3 rounded-xl border text-sm font-bold bg-purple-500/10 text-purple-500 border-purple-500/20 hover:bg-purple-500/20"
                >
                  <RefreshCw size={18} className="mx-auto" />
                </button>
              </div>
            </div>

            {/* Right Column: Result & Graph */}
            <div className="space-y-6">
              <div className={`p-8 rounded-3xl border flex flex-col items-center justify-center text-center ${isDarkMode ? 'bg-blue-900/10 border-blue-500/20 shadow-glow-dark' : 'bg-blue-50 border-blue-200 shadow-glow'
                }`}>
                <h3 className={`text-sm font-bold uppercase mb-4 ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>
                  Result
                </h3>
                <div className="w-full overflow-x-auto py-4 relative group/result">
                  <button
                    onClick={() => copyResult(result.result)}
                    className="absolute right-0 top-0 p-2 rounded-lg bg-blue-500/10 hover:bg-blue-500/20 opacity-0 group-hover/result:opacity-100 transition-all"
                    title="Copy Result"
                  >
                    <Copy size={16} className="text-blue-500" />
                  </button>
                  {result.error ? (
                    <div className="flex items-center justify-center text-red-500 space-x-2">
                      <AlertCircle size={20} />
                      <span>{result.error}</span>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <BlockMath math={result.latex} />
                      <div className="text-3xl font-black font-mono">
                        {activeTab === 'indefinite' ? '' : `= ${result.result}`}
                      </div>
                      {activeTab === 'indefinite' && (
                        <div className="text-xl font-bold text-blue-500">
                          <BlockMath math={result.result} />
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>

              {/* Graph Visualization */}
              {activeTab === 'definite' && chartData && (
                <div className={`p-6 rounded-3xl border ${isDarkMode ? 'bg-gray-900/50 border-gray-700' : 'bg-white border-gray-200'}`}>
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center space-x-2">
                      <ChartIcon size={18} className="text-blue-500" />
                      <span className="text-sm font-bold">Area Visualization</span>
                    </div>
                  </div>
                  <div className="h-[250px]">
                    <Line
                      data={chartData}
                      options={{
                        responsive: true,
                        maintainAspectRatio: false,
                        plugins: { legend: { display: false } },
                        scales: {
                          x: { grid: { display: false }, ticks: { display: false } },
                          y: { grid: { color: isDarkMode ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)' } }
                        }
                      }}
                    />
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Solution Engine */}
      {!result.error && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className={`p-8 rounded-3xl border shadow-xl ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'
            }`}
        >
          <div className="flex items-center space-x-4 mb-10">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white shadow-lg">
              <CheckCircle2 size={24} />
            </div>
            <div>
              <h2 className={`text-2xl font-black ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>
                Step-by-Step Integration
              </h2>
              <p className="text-sm text-gray-500">Breakdown of the antiderivative and bounds evaluation</p>
            </div>
          </div>

          <div className="space-y-0">
            {result.steps.map((step, idx) => (
              <SolutionStep
                key={idx}
                stepNumber={idx + 1}
                title={step.title}
                description={step.description}
                formula={step.formula}
                isLast={step.isLast}
                isDarkMode={isDarkMode}
              />
            ))}
          </div>
        </motion.div>
      )}

      {/* Educational Features: Cheat Sheet & Reference */}
      <div className="grid lg:grid-cols-2 gap-8">
        {/* Integration Cheat Sheet */}
        <div className={`p-8 rounded-3xl border ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'}`}>
          <div className="flex items-center space-x-3 mb-6">
            <Table size={20} className="text-blue-500" />
            <h3 className={`text-xl font-bold ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Common Integrals</h3>
          </div>
          <div className="space-y-4">
            <div className="flex justify-between p-3 rounded-xl bg-gray-500/5 border border-gray-500/10">
              <InlineMath math="\int x^n \, dx" />
              <InlineMath math="\frac{x^{n+1}}{n+1} + C" />
            </div>
            <div className="flex justify-between p-3 rounded-xl bg-gray-500/5 border border-gray-500/10">
              <InlineMath math="\int e^x \, dx" />
              <InlineMath math="e^x + C" />
            </div>
            <div className="flex justify-between p-3 rounded-xl bg-gray-500/5 border border-gray-500/10">
              <InlineMath math="\int \sin(x) \, dx" />
              <InlineMath math="-\cos(x) + C" />
            </div>
            <div className="flex justify-between p-3 rounded-xl bg-gray-500/5 border border-gray-500/10">
              <InlineMath math="\int \frac{1}{x} \, dx" />
              <InlineMath math="\ln|x| + C" />
            </div>
          </div>
        </div>

        {/* Integration Rules */}
        <div className={`p-8 rounded-3xl border ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'}`}>
          <div className="flex items-center space-x-3 mb-6">
            <HelpCircle size={20} className="text-purple-500" />
            <h3 className={`text-xl font-bold ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Integration Rules</h3>
          </div>
          <div className="space-y-4">
            <div className="flex flex-col p-3 rounded-xl bg-gray-500/5 border border-gray-500/10">
              <span className="text-xs font-bold text-gray-400 uppercase mb-1">Sum Rule</span>
              <InlineMath math="\int [f(x) \pm g(x)] \, dx = \int f(x) \, dx \pm \int g(x) \, dx" />
            </div>
            <div className="flex flex-col p-3 rounded-xl bg-gray-500/5 border border-gray-500/10">
              <span className="text-xs font-bold text-gray-400 uppercase mb-1">Constant Multiple</span>
              <InlineMath math="\int c \cdot f(x) \, dx = c \cdot \int f(x) \, dx" />
            </div>
          </div>
        </div>
      </div>

      {/* SEO Article */}
      <article className={`p-10 rounded-3xl border ${isDarkMode ? 'bg-gray-800/40 border-gray-700/50' : 'bg-white/40 border-gray-200/50'}`}>
        <h2 className={`text-4xl font-black mb-8 ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>
          The Student's Guide to Integration: From Antiderivatives to Net Area
        </h2>
        <div className={`prose prose-lg max-w-none ${isDarkMode ? 'prose-invert prose-gray-300' : 'prose-gray-600'}`}>
          <p>
            Integration is one of the most powerful tools in mathematics. While differentiation tells us how
            a function is changing at a specific point, integration allows us to see the total accumulation
            of those changes over time.
          </p>

          <h3 className="text-2xl font-bold mt-10 mb-4">Indefinite vs. Definite Integrals</h3>
          <p>
            Understanding the difference between indefinite and definite integrals is the first step toward
            mastering calculus:
          </p>
          <ul>
            <li>
              <strong>Indefinite Integrals:</strong> Also known as antiderivatives, these represent a family
              of functions. Because the derivative of a constant is zero, we always add the constant of
              integration ($+ C$) to the end of our result.
            </li>
            <li>
              <strong>Definite Integrals:</strong> These calculate the net signed area between a function
              and the x-axis within specific boundaries ($a$ and $b$). The result is always a number.
            </li>
          </ul>

          <h3 className="text-2xl font-bold mt-10 mb-4">Fundamental Theorem of Calculus</h3>
          <p>
            The Fundamental Theorem of Calculus (FTC) provides the link between derivatives and integrals.
            It states that to find the definite integral of a function, you can simply find its antiderivative
            and subtract the value at the lower bound from the value at the upper bound.
          </p>
          <BlockMath math="\int_a^b f(x) \, dx = F(b) - F(a)" />

          <h3 className="text-2xl font-bold mt-10 mb-4">Common Integration Challenges</h3>
          <p>
            Students often struggle with integration because there is no "Product Rule" or "Chain Rule"
            that works for every situation. Instead, integration requires recognizing patterns and applying
            techniques like:
          </p>
          <ul>
            <li><strong>U-Substitution:</strong> Used to reverse the Chain Rule.</li>
            <li><strong>Integration by Parts:</strong> Used to reverse the Product Rule.</li>
            <li><strong>Partial Fractions:</strong> Used for integrating rational functions.</li>
          </ul>
        </div>
      </article>
    </div>
  );
};

export default IntegralCalculator;
